fun loadExplorerFolder(path: String) {
    explorerCategory = "Internal Storage"
    explorerPath = path
    isScanningExplorer = true
    viewModelScope.launch(Dispatchers.IO) {
        val results = FileScanner.getDirectoryContents(path, currentSortOrder)
        withContext(Dispatchers.Main) {
            explorerFiles = results
            isScanningExplorer = false
        }
